import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { Box, Card, CardContent, Typography, CircularProgress, TextField } from "@mui/material";
import { format, parseISO, isSameDay, isThisMonth, isThisYear } from "date-fns"; // Importing date-fns functions

function ComDetails() {
  const { company_id } = useParams();
  const [workReports, setWorkReports] = useState([]);
  const [filteredReports, setFilteredReports] = useState([]);
  const [companyName, setCompanyName] = useState("");
  const [employees, setEmployees] = useState({});
  const [loading, setLoading] = useState(true);
  const [searchDate, setSearchDate] = useState("");
  const [searchEmployee, setSearchEmployee] = useState("");
  const [todayCount, setTodayCount] = useState(0);
  const [thisMonthCount, setThisMonthCount] = useState(0);
  const [thisYearCount, setThisYearCount] = useState(0);

  useEffect(() => {
    const fetchData = async () => {
      try {
        // Fetch Work Reports for the given company
        const workResponse = await fetch(`http://localhost:5000/companies/${company_id}/work-reports`);
        const workData = await workResponse.json();

        // Log the data to inspect its structure
        console.log("Fetched work data:", workData);

        // Ensure workData is an array before attempting to sort
        if (Array.isArray(workData)) {
          // Sort reports by last modified (latest first)
          workData.sort((a, b) => new Date(b.date) - new Date(a.date));
          setWorkReports(workData);
          setFilteredReports(workData);
        } else {
          throw new Error("Work data is not an array");
        }

        // Fetch Employee Details
        const employeeResponse = await fetch("http://localhost:5000/auth");
        const employeeData = await employeeResponse.json();
        const employeeMap = {};
        employeeData.forEach(employee => {
          employeeMap[employee.id] = employee.name;
        });
        setEmployees(employeeMap);

        // Fetch Company Details
        const companyResponse = await fetch(`http://localhost:5000/companies/${company_id}`);
        const companyData = await companyResponse.json();
        setCompanyName(companyData.company_name);

        setLoading(false);
      } catch (error) {
        console.error("Error fetching data:", error);
        setLoading(false);
      }
    };

    fetchData();
  }, [company_id]);

  // Calculate Counts for Today, This Month, and This Year
  useEffect(() => {
    const today = new Date();
    let todayCount = 0;
    let thisMonthCount = 0;
    let thisYearCount = 0;

    workReports.forEach((report) => {
      const reportDate = parseISO(report.date);

      if (isSameDay(reportDate, today)) {
        todayCount++;
      }
      if (isThisMonth(reportDate)) {
        thisMonthCount++;
      }
      if (isThisYear(reportDate)) {
        thisYearCount++;
      }
    });

    setTodayCount(todayCount);
    setThisMonthCount(thisMonthCount);
    setThisYearCount(thisYearCount);

    // Filter reports based on the search parameters
    let filtered = workReports;

    if (searchDate) {
      const parsedSearchDate = parseISO(searchDate); // Parse the search date
      filtered = filtered.filter(report => isSameDay(parseISO(report.date), parsedSearchDate));
    }

    if (searchEmployee) {
      filtered = filtered.filter(report =>
        employees[report.employee_id]?.toLowerCase().includes(searchEmployee.toLowerCase())
      );
    }

    setFilteredReports(filtered);
  }, [workReports, searchDate, searchEmployee, employees]);

  return (
    <Box sx={{ padding: 3, maxWidth: 800, margin: "auto" }}>
      <Typography variant="h4" sx={{ textAlign: "center", marginBottom: 2 }}>
        Work Reports - {companyName}
      </Typography>

      {/* Display Counts in a Box */}
      <Box sx={{ display: "flex", gap: 2, marginBottom: 2, justifyContent: "center" }}>
        <Box sx={{ padding: 2, backgroundColor: "#f0f0f0", borderRadius: 1, boxShadow: 2 }}>
          <Typography variant="h6">Reports Today: {todayCount}</Typography>
        </Box>
        <Box sx={{ padding: 2, backgroundColor: "#f0f0f0", borderRadius: 1, boxShadow: 2 }}>
          <Typography variant="h6">Reports This Month: {thisMonthCount}</Typography>
        </Box>
        <Box sx={{ padding: 2, backgroundColor: "#f0f0f0", borderRadius: 1, boxShadow: 2 }}>
          <Typography variant="h6">Reports This Year: {thisYearCount}</Typography>
        </Box>
      </Box>

      {/* Search Inputs */}
      <Box sx={{ display: "flex", gap: 2, marginBottom: 2 }}>
        <TextField
          label="Search by Date"
          type="date"
          InputLabelProps={{ shrink: true }}
          value={searchDate}
          onChange={(e) => setSearchDate(e.target.value)}
          fullWidth
        />
        <TextField
          label="Search by Employee Name"
          value={searchEmployee}
          onChange={(e) => setSearchEmployee(e.target.value)}
          fullWidth
        />
      </Box>

      {/* Loading Spinner */}
      {loading ? (
        <Box sx={{ textAlign: "center", marginTop: 4 }}>
          <CircularProgress />
        </Box>
      ) : filteredReports.length > 0 ? (
        filteredReports.map((report) => (
          <Card key={report.id} sx={{ marginBottom: 2, padding: 2, boxShadow: 3 }}>
            <CardContent>
              <Typography variant="h6" sx={{ fontWeight: "bold" }}>
                {employees[report.employee_id] || "Unknown"}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Date: {format(parseISO(report.date), "dd/MM/yyyy")}
              </Typography>
              <Typography variant="body2">
                <strong>Machine Name:</strong>  {report.machine_name}
              </Typography>
              <Typography variant="body2">
                <strong>Nature of Complaint:</strong> {report.nature_of_complaint}
              </Typography>
              <Typography variant="body2">
                <strong>Solution:</strong> {report.solution}
              </Typography>
              <Typography variant="body2">
                <strong>Time:</strong> {new Date(report.in_time).toLocaleTimeString()} - {new Date(report.out_time).toLocaleTimeString()}
              </Typography>
              <Typography variant="body2">
                <strong>Status:</strong> {report.status}
              </Typography>
              <Typography variant="body2">
                <strong>Assistant:</strong> {report.assistant_name}
              </Typography>
            </CardContent>
          </Card>
        ))
      ) : (
        <Typography sx={{ textAlign: "center", marginTop: 4 }}>No work reports found.</Typography>
      )}
    </Box>
  );
}

export default ComDetails;
